// Normalize the LLM's tool args into a uniform { query_name } shape.
// Stage 113 (verified end-to-end on tgbot15 with the operator's real Telegram
// message): the toolWorkflow node has `specifyInputSchema:false`, so the LLM
// passes a single RAW STRING as the tool's arg (no JSON wrapping). With the
// trigger in passthrough mode, that string arrives at $json.query. Stage 110's
// workflowInputs path + Stage 112's schemaType:"fromJson" both failed (the LLM
// kept sending query_name:null in those modes — confirmed via DEBUG1+DEBUG2
// Telegram messages on tgbot14/15). This normalizer tries every observed shape
// in order so the Switch downstream can read `$json.query_name` uniformly.
const items = $input.all();
const raw = (items[0] && items[0].json) || {};
const valid = ['style_profile_get', 'recent_audit_log', 'pending_actions_open', 'executions_summary_24h', 'spend_total', 'conversation_transcript', 'tool_trace_recent', 'claim_actual_mismatch'];
const tryString = (s) => {
  if (typeof s !== 'string') return '';
  const t = s.trim();
  if (!t) return '';
  if (valid.indexOf(t) >= 0) return t;
  try { const p = JSON.parse(t); if (p && typeof p.query_name === 'string') return p.query_name; } catch (e) { /* ignore */ }
  return '';
};
let qn = '';
if (typeof raw.query_name === 'string' && raw.query_name) {
  qn = raw.query_name;
} else if (typeof raw.query === 'string') {
  qn = tryString(raw.query);
} else if (raw.query && typeof raw.query === 'object' && typeof raw.query.query_name === 'string') {
  qn = raw.query.query_name;
} else if (raw.input && typeof raw.input.query_name === 'string') {
  qn = raw.input.query_name;
} else if (typeof raw.arguments === 'string') {
  qn = tryString(raw.arguments);
}
return [{ json: { query_name: qn, _raw_input: raw } }];

// Format any of the Postgres branch outputs into a uniform tool response.
// Postgres nodes with alwaysOutputData:true emit one empty {} when SELECT returns
// zero rows; filter that out so the LLM sees rows:[] rather than rows:[{}].
// query_name comes from the Normalize Input node (Stage 111) which extracts it
// defensively from any of the possible toolWorkflow payload shapes.
const normalized = $('Normalize Input').first().json || {};
const rows = $input.all()
  .map(i => i.json)
  .filter(o => o && typeof o === 'object' && Object.keys(o).length > 0);
return [{ json: { ok: true, query_name: String(normalized.query_name || ''), rows: rows } }];

// bot-trace-observability: mint a per-tool-call id + a SQL-safe input summary.
// tool_call_id is generated in JS (same idiom as request-write-action's
// idempotency_key) so every downstream trace node references it by name.
// esc() doubles single quotes (the repo's SQL-safe convention) so arbitrary
// LLM input can never break the INSERT. onError on the writers keeps the bot safe.
const j = ($input.first() && $input.first().json) || {};
const esc = (s) => String(s).replace(/'/g, "''");
const toolCallId = Date.now() + '-' + Math.random().toString(36).slice(2, 12);
let summary = '';
try { summary = JSON.stringify({ query_name: j.query_name || '', raw: j._raw_input || {} }); } catch (e) { summary = '{}'; }
if (summary.length > 2000) { summary = summary.slice(0, 2000); }
return [{ json: { query_name: j.query_name || '', _raw_input: j._raw_input || {}, tool_call_id: toolCallId, input_summary_sql: esc(summary) } }];

// bot-trace-observability: re-assert the original tool payload as the LAST node
// on the path, so this toolWorkflow returns {ok,query_name,rows} to the LLM —
// NOT the trace UPDATE result. Reads Format Output by name (robust to the trace
// write clobbering $json).
return [{ json: $('Format Output').first().json }];
